############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserFormulaWithUnits.pl", "parserNumberWithUnits.pl", "contextForm.pl", "contextFraction.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
