############################################################ # PG Setup Code ############################################################ $initial = random(20,25); $start = NumberWithUnits("$initial psi"); Context("Fraction"); $rate = list_random( [3,2], [5,2], [4,3], [5,3], [7,3], [8,3], [5,4], [7,4], [9,4], [11,4], [6,5], [7,5], [8,5], [9,5], [11,5], [12,5], [13,5], [14,5], [7,6], [11,6], [13,6], [17,6] ); $rate = Fraction(($rate->[0])/($rate->[1])); $speed = FormulaWithUnits("$rate psi/min"); $final = random(30,34); $end = NumberWithUnits("$final psi"); $solution = ($final - $initial)/$rate; Context("Numeric")->flags->set(reduceConstants => 0); $time = FormulaWithUnits("$solution min");
############################################################ # Body ############################################################
BEGIN_PGML One of the tires on your car looks a little flat. You measure its air pressure and are alarmed to see it so low at [`[$start]\text{.}`] You have a portable device that can pump air into the tire increasing the pressure at a rate of [`[$speed]\text{.}`] How long will it take to fill the tire to the manual's recommended pressure of [`[$end]\text{?}`]
[_]{$time}{20}
END_PGML
